import { getImportedComponentName, isExperimentalImport, isHubspotExtensibilityImport, isRelativeImport, } from "../../utils/import-utils.js";
describe('import-utils', () => {
    describe('isHubspotExtensibilityImport', () => {
        it('should return true for @hubspot/ui-extensions imports', () => {
            expect(isHubspotExtensibilityImport('@hubspot/ui-extensions')).toBe(true);
            expect(isHubspotExtensibilityImport('@hubspot/ui-extensions/crm')).toBe(true);
            expect(isHubspotExtensibilityImport('@hubspot/ui-extensions/crm/hooks')).toBe(true);
            expect(isHubspotExtensibilityImport('@hubspot/ui-extensions/settings')).toBe(true);
        });
        it('should return false for non-hubspot imports', () => {
            expect(isHubspotExtensibilityImport('react')).toBe(false);
            expect(isHubspotExtensibilityImport('@other/package')).toBe(false);
            expect(isHubspotExtensibilityImport('lodash')).toBe(false);
        });
        it('should return false for other hubspot packages', () => {
            expect(isHubspotExtensibilityImport('@hubspot/other-package')).toBe(false);
            expect(isHubspotExtensibilityImport('@hubspot/cms')).toBe(false);
        });
        it('should return false for non-string values', () => {
            expect(isHubspotExtensibilityImport(null)).toBe(false);
            expect(isHubspotExtensibilityImport(undefined)).toBe(false);
            expect(isHubspotExtensibilityImport(123)).toBe(false);
            expect(isHubspotExtensibilityImport({})).toBe(false);
            expect(isHubspotExtensibilityImport([])).toBe(false);
        });
        it('should return false for empty string', () => {
            expect(isHubspotExtensibilityImport('')).toBe(false);
        });
    });
    describe('getImportedComponentName', () => {
        it('should return the local name for a regular import', () => {
            const node = {
                type: 'ImportDeclaration',
                specifiers: [
                    {
                        type: 'ImportSpecifier',
                        imported: { type: 'Identifier', name: 'Image' },
                        local: { type: 'Identifier', name: 'Image' },
                    },
                ],
                source: { type: 'Literal', value: '@hubspot/ui-extensions' },
                attributes: [],
            };
            expect(getImportedComponentName(node, 'Image')).toBe('Image');
        });
        it('should return the local name for an aliased import', () => {
            const node = {
                type: 'ImportDeclaration',
                specifiers: [
                    {
                        type: 'ImportSpecifier',
                        imported: { type: 'Identifier', name: 'Image' },
                        local: { type: 'Identifier', name: 'HubImage' },
                    },
                ],
                source: { type: 'Literal', value: '@hubspot/ui-extensions' },
                attributes: [],
            };
            expect(getImportedComponentName(node, 'Image')).toBe('HubImage');
        });
        it('should return null when component is not imported', () => {
            const node = {
                type: 'ImportDeclaration',
                specifiers: [
                    {
                        type: 'ImportSpecifier',
                        imported: { type: 'Identifier', name: 'Button' },
                        local: { type: 'Identifier', name: 'Button' },
                    },
                ],
                source: { type: 'Literal', value: '@hubspot/ui-extensions' },
                attributes: [],
            };
            expect(getImportedComponentName(node, 'Image')).toBeNull();
        });
        it('should return null for empty specifiers', () => {
            const node = {
                type: 'ImportDeclaration',
                specifiers: [],
                source: { type: 'Literal', value: '@hubspot/ui-extensions' },
                attributes: [],
            };
            expect(getImportedComponentName(node, 'Image')).toBeNull();
        });
        it('should find the component among multiple imports', () => {
            const node = {
                type: 'ImportDeclaration',
                specifiers: [
                    {
                        type: 'ImportSpecifier',
                        imported: { type: 'Identifier', name: 'Button' },
                        local: { type: 'Identifier', name: 'Button' },
                    },
                    {
                        type: 'ImportSpecifier',
                        imported: { type: 'Identifier', name: 'Image' },
                        local: { type: 'Identifier', name: 'MyImage' },
                    },
                    {
                        type: 'ImportSpecifier',
                        imported: { type: 'Identifier', name: 'Text' },
                        local: { type: 'Identifier', name: 'Text' },
                    },
                ],
                source: { type: 'Literal', value: '@hubspot/ui-extensions' },
                attributes: [],
            };
            expect(getImportedComponentName(node, 'Image')).toBe('MyImage');
        });
    });
    describe('isRelativeImport', () => {
        it('should return true for relative imports starting with ./', () => {
            expect(isRelativeImport('./utils')).toBe(true);
            expect(isRelativeImport('./components/Button')).toBe(true);
            expect(isRelativeImport('./hooks/useData')).toBe(true);
            expect(isRelativeImport('./')).toBe(true);
        });
        it('should return true for relative imports starting with ../', () => {
            expect(isRelativeImport('../utils')).toBe(true);
            expect(isRelativeImport('../shared/constants')).toBe(true);
            expect(isRelativeImport('../../lib/helpers')).toBe(true);
            expect(isRelativeImport('../')).toBe(true);
        });
        it('should return false for npm package imports', () => {
            expect(isRelativeImport('react')).toBe(false);
            expect(isRelativeImport('lodash')).toBe(false);
            expect(isRelativeImport('axios')).toBe(false);
        });
        it('should return false for scoped package imports', () => {
            expect(isRelativeImport('@hubspot/ui-extensions')).toBe(false);
            expect(isRelativeImport('@company/package')).toBe(false);
            expect(isRelativeImport('@babel/core')).toBe(false);
        });
        it('should return false for absolute imports', () => {
            expect(isRelativeImport('/absolute/path')).toBe(false);
            expect(isRelativeImport('/src/app/cards')).toBe(false);
        });
        it('should return false for imports starting with dot but not followed by slash', () => {
            expect(isRelativeImport('.')).toBe(false);
            expect(isRelativeImport('..')).toBe(false);
            expect(isRelativeImport('...utils')).toBe(false);
        });
        it('should return false for non-string values', () => {
            expect(isRelativeImport(null)).toBe(false);
            expect(isRelativeImport(undefined)).toBe(false);
            expect(isRelativeImport(123)).toBe(false);
            expect(isRelativeImport({})).toBe(false);
            expect(isRelativeImport([])).toBe(false);
        });
        it('should return false for empty string', () => {
            expect(isRelativeImport('')).toBe(false);
        });
    });
    describe('isExperimentalImport', () => {
        it('should return true for @hubspot/ui-extensions/experimental', () => {
            expect(isExperimentalImport('@hubspot/ui-extensions/experimental')).toBe(true);
        });
        it('should return true for experimental subpaths', () => {
            expect(isExperimentalImport('@hubspot/ui-extensions/experimental/Layout')).toBe(true);
            expect(isExperimentalImport('@hubspot/ui-extensions/experimental/Layout/Grid')).toBe(true);
        });
        it('should return false for stable @hubspot/ui-extensions imports', () => {
            expect(isExperimentalImport('@hubspot/ui-extensions')).toBe(false);
            expect(isExperimentalImport('@hubspot/ui-extensions/crm')).toBe(false);
            expect(isExperimentalImport('@hubspot/ui-extensions/hooks')).toBe(false);
        });
        it('should return false for non-hubspot packages', () => {
            expect(isExperimentalImport('react')).toBe(false);
            expect(isExperimentalImport('some-package/experimental')).toBe(false);
        });
        it('should return false for non-string values', () => {
            expect(isExperimentalImport(null)).toBe(false);
            expect(isExperimentalImport(undefined)).toBe(false);
        });
    });
});
